class GetAllNotifications {
  GetAllNotifications({
      this.isSuccess, 
      this.message, 
      this.data,});

  GetAllNotifications.fromJson(dynamic json) {
    isSuccess = json['isSuccess'];
    message = json['message'];
    data = json['data'] != null ? Data.fromJson(json['data']) : null;
  }
  bool? isSuccess;
  String? message;
  Data? data;
GetAllNotifications copyWith({  bool? isSuccess,
  String? message,
  Data? data,
}) => GetAllNotifications(  isSuccess: isSuccess ?? this.isSuccess,
  message: message ?? this.message,
  data: data ?? this.data,
);
  Map<String, dynamic> toJson() {
    final map = <String, dynamic>{};
    map['isSuccess'] = isSuccess;
    map['message'] = message;
    if (data != null) {
      map['data'] = data?.toJson();
    }
    return map;
  }

}

