class Data {
  Data({
      this.allNotifications, 
      this.today, 
      this.yesterday, 
      this.last7Days, 
      this.older,});

  Data.fromJson(dynamic json) {
    if (json['allNotifications'] != null) {
      allNotifications = [];
      json['allNotifications'].forEach((v) {
        allNotifications?.add(AllNotifications.fromJson(v));
      });
    }
    if (json['today'] != null) {
      today = [];
      json['today'].forEach((v) {
        today?.add(Today.fromJson(v));
      });
    }
    if (json['yesterday'] != null) {
      yesterday = [];
      json['yesterday'].forEach((v) {
        yesterday?.add(Yesterday.fromJson(v));
      });
    }
    if (json['last7Days'] != null) {
      last7Days = [];
      json['last7Days'].forEach((v) {
        last7Days?.add(Last7Days.fromJson(v));
      });
    }
    if (json['older'] != null) {
      older = [];
      json['older'].forEach((v) {
        older?.add(Older.fromJson(v));
      });
    }
  }
  List<AllNotifications>? allNotifications;
  List<Today>? today;
  List<Yesterday>? yesterday;
  List<Last7Days>? last7Days;
  List<Older>? older;
Data copyWith({  List<AllNotifications>? allNotifications,
  List<Today>? today,
  List<Yesterday>? yesterday,
  List<Last7Days>? last7Days,
  List<Older>? older,
}) => Data(  allNotifications: allNotifications ?? this.allNotifications,
  today: today ?? this.today,
  yesterday: yesterday ?? this.yesterday,
  last7Days: last7Days ?? this.last7Days,
  older: older ?? this.older,
);
  Map<String, dynamic> toJson() {
    final map = <String, dynamic>{};
    if (allNotifications != null) {
      map['allNotifications'] = allNotifications?.map((v) => v.toJson()).toList();
    }
    if (today != null) {
      map['today'] = today?.map((v) => v.toJson()).toList();
    }
    if (yesterday != null) {
      map['yesterday'] = yesterday?.map((v) => v.toJson()).toList();
    }
    if (last7Days != null) {
      map['last7Days'] = last7Days?.map((v) => v.toJson()).toList();
    }
    if (older != null) {
      map['older'] = older?.map((v) => v.toJson()).toList();
    }
    return map;
  }

}

